@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.IComponentInteropService Interop
@inject Microsoft.Extensions.Options.IOptions<Lumeo.Services.LumeoGestureOptions> GestureOpts
@implements IAsyncDisposable

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (NumberOfMonths == 1)
    {
        @RenderMonth(DisplayDate)
    }
    else
    {
        <div class="flex gap-4">
            @for (var i = 0; i < NumberOfMonths; i++)
            {
                var monthDate = DisplayDate.AddMonths(i);
                <div>
                    @RenderMonth(monthDate, showPrev: i == 0, showNext: i == NumberOfMonths - 1)
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public DateOnly? Value { get; set; }
    [Parameter] public EventCallback<DateOnly?> ValueChanged { get; set; }
    [Parameter] public DateOnly? MinDate { get; set; }
    [Parameter] public DateOnly? MaxDate { get; set; }
    [Parameter] public bool IsRange { get; set; }
    [Parameter] public DateOnly? RangeStart { get; set; }
    [Parameter] public EventCallback<DateOnly?> RangeStartChanged { get; set; }
    [Parameter] public DateOnly? RangeEnd { get; set; }
    [Parameter] public EventCallback<DateOnly?> RangeEndChanged { get; set; }
    /// <summary>When true the grid selects a set of independent days: clicking a
    /// day (or Enter/Space on it) toggles it in/out of <see cref="Values"/>.
    /// Takes precedence over single <see cref="Value"/> selection; ignored when
    /// <see cref="IsRange"/> is set.</summary>
    [Parameter] public bool IsMultiple { get; set; }
    /// <summary>The selected days in multiple-selection mode. Pair with
    /// <see cref="ValuesChanged"/> for two-way binding.</summary>
    [Parameter] public List<DateOnly>? Values { get; set; }
    [Parameter] public EventCallback<List<DateOnly>?> ValuesChanged { get; set; }
    [Parameter] public int NumberOfMonths { get; set; } = 1;
    [Parameter] public bool ShowWeekNumbers { get; set; }
    [Parameter] public bool ShowYearPicker { get; set; }
    [Parameter] public CalendarView InitialView { get; set; } = CalendarView.Days;
    [Parameter] public Func<DateTime, bool>? IsDateDisabled { get; set; }
    [Parameter] public Func<DateTime, string>? DateClass { get; set; }
    /// <summary>Optional per-date tooltip text. Returned string becomes the
    /// day cell's <c>title</c> attribute (native browser tooltip on hover).
    /// Return <c>null</c> or empty for no tooltip on that date. Useful for
    /// booking calendars: "Booked by John, 14:00–17:00" or "Sold out".</summary>
    [Parameter] public Func<DateTime, string?>? DateTooltip { get; set; }
    /// <summary>Optional per-date indicator slot. Returns a <c>RenderFragment</c>
    /// rendered absolutely positioned in the bottom-right of the day cell —
    /// good for status dots, count badges, icons. Return <c>null</c> for no
    /// badge on that date. The slot is non-interactive
    /// (<c>pointer-events-none</c>) so clicks still hit the day button.</summary>
    [Parameter] public Func<DateTime, RenderFragment?>? DateBadge { get; set; }
    /// <summary>The day of the week to render in the leftmost column.
    /// When <c>null</c> (default), uses
    /// <c>CultureInfo.CurrentCulture.DateTimeFormat.FirstDayOfWeek</c> —
    /// so de-DE / fr-FR / etc. start on Monday automatically, en-US on
    /// Sunday. Pass an explicit <see cref="DayOfWeek"/> to override.</summary>
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }
    /// <summary>When <c>true</c> (default), users can swipe left/right on the
    /// day grid to navigate to the next or previous month on touch devices.
    /// Vertical page scroll is unaffected (<c>touch-action: pan-y</c>).
    /// Set to <c>false</c> to disable swipe navigation.</summary>
    [Parameter] public bool SwipeEnabled { get; set; } = true;

    private readonly string _elementId = LumeoIds.New("cal-grid");

    private DayOfWeek EffectiveFirstDayOfWeek =>
        FirstDayOfWeek ?? System.Globalization.CultureInfo.CurrentCulture.DateTimeFormat.FirstDayOfWeek;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private DateOnly DisplayDate { get; set; }
    private DateOnly? _hoverDate;
    private CalendarView _currentView = CalendarView.Days;
    private bool _swipeAttached;
    // Roving-tabindex focus target for keyboard grid navigation (WAI-ARIA grid
    // pattern). Exactly one day button is tabbable (tabindex=0) — the focused
    // day — every other day carries tabindex=-1. Lazily seeded from the
    // selected/today/first-of-month day so the initial Tab lands somewhere sane.
    private DateOnly? _focusedDate;
    // Tracks the id the prevent-default-keys listener was registered against so
    // we can re-register when the day-grid element id changes and unregister on
    // dispose (mirrors TreeViewNode's page-scroll suppression).
    private string? _pdRegisteredId;
    // Last-seen bound anchor (Value, or RangeStart in range mode). Used to
    // detect *external* value changes in OnParametersSet without stomping the
    // user's manual month navigation on unrelated re-renders.
    private DateOnly? _lastSeenAnchor;

    private string CssClass => Cx.Merge("p-3", Class);

    protected override void OnInitialized()
    {
        // ShowYearPicker is a convenience shortcut that opens straight into the
        // year-picker view. When set it wins over InitialView so consumers can
        // request the year grid without knowing the CalendarView enum.
        _currentView = ShowYearPicker ? CalendarView.Years : InitialView;
        // CurrentAnchor folds in multiple/range/single precedence so the
        // displayed month seeds correctly regardless of selection mode.
        _lastSeenAnchor = CurrentAnchor;
        DisplayDate = _lastSeenAnchor ?? DateOnly.FromDateTime(DateTime.Today);
    }

    protected override void OnParametersSet()
    {
        // When the bound anchor (Value, RangeStart, or the first selected day in
        // multiple mode) changes from outside — e.g. the parent sets it
        // programmatically on an inline calendar — navigate the visible month to
        // it. Only react to actual changes: re-renders that leave the anchor
        // untouched must not reset manual browsing.
        var anchor = CurrentAnchor;
        if (anchor != _lastSeenAnchor)
        {
            _lastSeenAnchor = anchor;
            if (anchor.HasValue)
            {
                DisplayDate = new DateOnly(anchor.Value.Year, anchor.Value.Month, 1);
            }
        }
    }

    // The day the displayed month tracks for external value changes: in
    // multiple mode the earliest selected day, in range mode the start, else
    // the single Value.
    private DateOnly? CurrentAnchor =>
        IsMultiple ? (Values is { Count: > 0 } ? Values.Min() : null)
        : IsRange ? RangeStart
        : Value;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // The id-bearing day grid element exists only for a single-month Days
        // view (the gridId in RenderMonth is null for multi-month panels, which
        // share one component, and for the Months/Years pickers). Both the swipe
        // handler and the page-scroll suppression for the keyboard-nav keys
        // attach to that element, so they must (un)register as the grid appears
        // and disappears — including a NumberOfMonths 1→2→1 round-trip. An early
        // `if (NumberOfMonths != 1) return;` here would skip teardown on the way
        // out and re-registration on the way back, permanently orphaning both.
        var hasSingleGrid = NumberOfMonths == 1 && _currentView == CalendarView.Days;

        if (hasSingleGrid && SwipeEnabled && !_swipeAttached)
        {
            _swipeAttached = true;
            try { await Interop.RegisterHorizontalSwipe(_elementId, OnSwipeAsync, GestureOpts.Value.SwipeThresholdPx, GestureOpts.Value.VerticalDeadZonePx); }
            catch (JSDisconnectedException) { _swipeAttached = false; }
            catch (InvalidOperationException) { _swipeAttached = false; } // JS unavailable during prerender
        }
        else if ((!hasSingleGrid || !SwipeEnabled) && _swipeAttached)
        {
            _swipeAttached = false;
            try { await Interop.UnregisterHorizontalSwipe(_elementId); }
            catch (JSDisconnectedException) { }
        }

        // Suppress page scroll for the arrow / Home / End / PageUp / PageDown
        // keys while the day grid is visible — without this the first keypress
        // scrolls the page as focus also moves (same pattern as TreeViewNode).
        if (hasSingleGrid && _pdRegisteredId != _elementId)
        {
            try
            {
                await Interop.RegisterPreventDefaultKeys(_elementId, NavKeyRules);
                _pdRegisteredId = _elementId;
            }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // JS unavailable during prerender
        }
        else if (!hasSingleGrid && _pdRegisteredId is not null)
        {
            try { await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId); }
            catch (JSDisconnectedException) { }
            _pdRegisteredId = null;
        }
    }

    // Keys whose browser default (page scroll) is suppressed on the day grid.
    private static readonly PreventDefaultKeyRule[] NavKeyRules =
    [
        new("ArrowLeft"), new("ArrowRight"), new("ArrowUp"), new("ArrowDown"),
        new("Home"), new("End"), new("PageUp"), new("PageDown"),
    ];

    private Task OnSwipeAsync(string direction)
    {
        if (_currentView != CalendarView.Days) return Task.CompletedTask;
        if (direction == "next" && !IsNextMonthDisabled)
            NextMonth();
        else if (direction == "prev" && !IsPrevMonthDisabled)
            PreviousMonth();
        StateHasChanged();
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        if (_swipeAttached)
        {
            try { await Interop.UnregisterHorizontalSwipe(_elementId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        if (_pdRegisteredId is not null)
        {
            try { await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private bool IsPrevMonthDisabled =>
        MinDate.HasValue && new DateOnly(DisplayDate.Year, DisplayDate.Month, 1) <= new DateOnly(MinDate.Value.Year, MinDate.Value.Month, 1);

    private bool IsNextMonthDisabled
    {
        get
        {
            var lastPanel = DisplayDate.AddMonths(NumberOfMonths - 1);
            return MaxDate.HasValue && new DateOnly(lastPanel.Year, lastPanel.Month, 1) >= new DateOnly(MaxDate.Value.Year, MaxDate.Value.Month, 1);
        }
    }

    private bool IsDisabled(DateOnly day) =>
        (MinDate.HasValue && day < MinDate.Value) || (MaxDate.HasValue && day > MaxDate.Value)
        || (IsDateDisabled != null && IsDateDisabled(day.ToDateTime(TimeOnly.MinValue)));

    private string[] GetDayHeaders()
    {
        // .NET's ShortestDayNames collapses to 1 letter per culture
        // ("S,M,T,W,T,F,S"), which is ambiguous in any language. Use
        // AbbreviatedDayNames and take the first two letters of each so we
        // get culture-correct, distinguishable headers:
        //   en-US → Su/Mo/Tu/We/Th/Fr/Sa
        //   de-DE → So/Mo/Di/Mi/Do/Fr/Sa
        //   fr-FR → di/lu/ma/me/je/ve/sa
        var abbr = System.Globalization.CultureInfo.CurrentCulture.DateTimeFormat.AbbreviatedDayNames;
        var startIndex = (int)EffectiveFirstDayOfWeek;
        var result = new string[7];
        for (var i = 0; i < 7; i++)
        {
            var raw = abbr[(startIndex + i) % 7];
            // Strip trailing punctuation (de-DE returns "So.", "Mo." …) before slicing.
            var letters = new string(raw.TakeWhile(char.IsLetter).ToArray());
            result[i] = letters.Length >= 2 ? letters[..2] : letters;
        }
        return result;
    }

    private List<DateOnly> GetCalendarDays(DateOnly monthDate)
    {
        var days = new List<DateOnly>();
        var firstOfMonth = new DateOnly(monthDate.Year, monthDate.Month, 1);
        var startOffset = ((int)firstOfMonth.DayOfWeek - (int)EffectiveFirstDayOfWeek + 7) % 7;
        var start = firstOfMonth.AddDays(-startOffset);

        for (var i = 0; i < 42; i++)
        {
            days.Add(start.AddDays(i));
        }
        return days;
    }

    private int GetIsoWeekNumber(DateOnly date)
    {
        var dt = date.ToDateTime(TimeOnly.MinValue);
        var day = System.Globalization.CultureInfo.InvariantCulture.Calendar.GetDayOfWeek(dt);
        if (day >= DayOfWeek.Monday && day <= DayOfWeek.Wednesday)
        {
            dt = dt.AddDays(3);
        }
        return System.Globalization.CultureInfo.InvariantCulture.Calendar.GetWeekOfYear(dt,
            System.Globalization.CalendarWeekRule.FirstFourDayWeek, DayOfWeek.Monday);
    }

    private int GetDecadeStart(int year) => year / 10 * 10;

    // Wrapper-div classes that render the connecting range bar BEHIND the
    // day button (2.1.4). Previously each in-range day's button had its own
    // rounded-md bg-accent rectangle, producing a pearl-necklace look with
    // visual gaps between days. The wrapper carries the bar background and
    // edge rounding so adjacent in-range cells touch seamlessly.
    //
    // Returns empty string for non-Range mode or days outside the range so
    // the wrapper has no styling and the button keeps its original look.
    //
    // Edge cases:
    // - First column on a row (col == 0) gets rounded-s-md so the bar starts
    //   with a rounded cap when the range wraps to a new row.
    // - Last column on a row (col == 6) gets rounded-e-md likewise.
    // - The range-start and range-end days get rounded-s-md / rounded-e-md
    //   so the bar terminates with a soft cap behind the primary circle.
    // - Hover during in-flight selection (RangeStart set, RangeEnd null,
    //   _hoverDate carries the preview) extends the bar dynamically.
    private string RangeBarClasses(DateOnly day, DateOnly monthDate, int col)
    {
        if (!IsRange) return "";

        var effectiveEnd = RangeEnd ?? (RangeStart.HasValue && _hoverDate.HasValue ? _hoverDate : null);
        var rangeFrom = RangeStart;
        var rangeTo = effectiveEnd;
        if (rangeFrom.HasValue && rangeTo.HasValue && rangeTo < rangeFrom)
        {
            (rangeFrom, rangeTo) = (rangeTo, rangeFrom);
        }
        if (!rangeFrom.HasValue || !rangeTo.HasValue) return "";
        if (day < rangeFrom.Value || day > rangeTo.Value) return "";

        var isStart = day == rangeFrom.Value;
        var isEnd = day == rangeTo.Value;

        // flex layout keeps the button (h-8 w-8) centered horizontally so the
        // surrounding bar extends to the cell edges on either side.
        var parts = new List<string> { "flex items-center justify-center bg-accent" };
        if (isStart || col == 0) parts.Add("rounded-s-md");
        if (isEnd || col == 6) parts.Add("rounded-e-md");
        return string.Join(" ", parts);
    }

    // The day-cell button, rendered either bare or as the AsChild trigger of a Lumeo
    // <Tooltip> (when DateTooltip yields a hint). slotAttrs carries aria-describedby
    // (only while the tooltip is open) so the button itself is described on focus.
    private RenderFragment RenderDay(DateOnly d, DateOnly monthDate, RenderFragment? badge, IReadOnlyDictionary<string, object>? slotAttrs) =>
        @<button type="button" id="@DayId(monthDate, d)" tabindex="@DayTabIndex(d, monthDate)"
                 aria-label="@DayAriaLabel(d)"
                 aria-pressed="@(IsMultiple ? ((Values?.Contains(d) ?? false) ? "true" : "false") : null)"
                 class="@DayClasses(d, monthDate)" disabled="@IsDisabled(d)"
                 @attributes="slotAttrs"
                 @onclick="() => SelectDay(d)" @onmouseenter="() => OnDayHover(d)"
                 @onfocus="() => OnDayFocus(d)"
                 @onkeydown="e => HandleDayKeyDownAsync(e, monthDate, d)">
            @d.Day
            @if (badge is not null)
            {
                <span class="absolute -bottom-0.5 -end-0.5 pointer-events-none flex">@badge</span>
            }
        </button>;

    private string DayClasses(DateOnly day, DateOnly monthDate)
    {
        var isCurrentMonth = day.Month == monthDate.Month;
        var isDisabled = IsDisabled(day);
        var isSelected = IsMultiple
            ? (Values?.Contains(day) ?? false)
            : (!IsRange && Value.HasValue && day == Value.Value);
        var isToday = day == DateOnly.FromDateTime(DateTime.Today);

        // 'relative' kept on every day so DateBadge slots can absolute-position inside.
        var baseClass = "relative inline-flex items-center justify-center rounded-md h-8 w-8 text-sm transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";
        var extraClass = DateClass != null ? DateClass(day.ToDateTime(TimeOnly.MinValue)) : "";

        if (isDisabled)
            return $"{baseClass} pointer-events-none opacity-50 {extraClass}".Trim();

        if (IsRange)
        {
            var isRangeStart = RangeStart.HasValue && day == RangeStart.Value;
            var isRangeEnd = RangeEnd.HasValue && day == RangeEnd.Value;

            var effectiveEnd = RangeEnd ?? (RangeStart.HasValue && _hoverDate.HasValue ? _hoverDate : null);
            var rangeFrom = RangeStart;
            var rangeTo = effectiveEnd;
            if (rangeFrom.HasValue && rangeTo.HasValue && rangeTo < rangeFrom)
            {
                (rangeFrom, rangeTo) = (rangeTo, rangeFrom);
            }

            var inRange = rangeFrom.HasValue && rangeTo.HasValue && day > rangeFrom.Value && day < rangeTo.Value;

            if (isRangeStart || isRangeEnd)
                return $"{baseClass} bg-primary text-primary-foreground font-medium {extraClass}".Trim();
            if (inRange)
                return $"{baseClass} bg-accent text-accent-foreground {extraClass}".Trim();
            if (isToday)
                return $"{baseClass} bg-accent text-accent-foreground font-medium {extraClass}".Trim();
            if (!isCurrentMonth)
                return $"{baseClass} text-muted-foreground/50 hover:bg-accent hover:text-accent-foreground {extraClass}".Trim();
            return $"{baseClass} hover:bg-accent hover:text-accent-foreground {extraClass}".Trim();
        }

        if (isSelected)
            return $"{baseClass} bg-primary text-primary-foreground font-medium {extraClass}".Trim();
        if (isToday)
            return $"{baseClass} bg-accent text-accent-foreground font-medium {extraClass}".Trim();
        if (!isCurrentMonth)
            return $"{baseClass} text-muted-foreground/50 hover:bg-accent hover:text-accent-foreground {extraClass}".Trim();
        return $"{baseClass} hover:bg-accent hover:text-accent-foreground {extraClass}".Trim();
    }

    private async Task SelectDay(DateOnly day)
    {
        if (IsDisabled(day)) return;

        // Keep the roving-tabindex target on the just-selected day so it stays
        // the tabbable cell (and keyboard focus stays put after Enter/Space).
        _focusedDate = day;

        if (IsMultiple)
        {
            // Toggle the day in/out of the selected set; keep the result sorted
            // so consumers get a stable, chronological list.
            var next = Values is null ? new List<DateOnly>() : new List<DateOnly>(Values);
            if (!next.Remove(day)) next.Add(day);
            next.Sort();
            Values = next;
            DisplayDate = new DateOnly(day.Year, day.Month, 1);
            await ValuesChanged.InvokeAsync(next);
            return;
        }

        if (IsRange)
        {
            if (!RangeStart.HasValue || (RangeStart.HasValue && RangeEnd.HasValue))
            {
                await RangeStartChanged.InvokeAsync(day);
                await RangeEndChanged.InvokeAsync(null);
                _hoverDate = null;
            }
            else
            {
                var start = RangeStart.Value;
                if (day < start)
                {
                    await RangeStartChanged.InvokeAsync(day);
                    await RangeEndChanged.InvokeAsync(start);
                }
                else
                {
                    await RangeEndChanged.InvokeAsync(day);
                }
                _hoverDate = null;
            }
            DisplayDate = new DateOnly(day.Year, day.Month, 1);
        }
        else
        {
            DisplayDate = new DateOnly(day.Year, day.Month, 1);
            Value = day;
            // Keep the external-change tracker aligned with this internal
            // mutation so an unrelated parent re-render later (uncontrolled
            // usage) doesn't read it as a new external value and yank the
            // display month away from wherever the user has browsed to.
            _lastSeenAnchor = day;
            await ValueChanged.InvokeAsync(day);
        }
    }

    private void OnDayHover(DateOnly day)
    {
        if (IsRange && RangeStart.HasValue && !RangeEnd.HasValue)
        {
            _hoverDate = day;
        }
    }

    // ---- WAI-ARIA grid keyboard navigation (roving tabindex) ----

    /// <summary>Whether <paramref name="day"/> renders as the selected day —
    /// drives <c>aria-selected</c> on the grid cell. In multiple mode every day
    /// in <see cref="Values"/> is selected; in range mode the two endpoints are
    /// the selected cells; otherwise the single <see cref="Value"/>.</summary>
    private bool IsDaySelected(DateOnly day) => IsMultiple
        ? (Values?.Contains(day) ?? false)
        : IsRange
            ? (RangeStart.HasValue && day == RangeStart.Value) || (RangeEnd.HasValue && day == RangeEnd.Value)
            : Value.HasValue && day == Value.Value;

    /// <summary>Deterministic per-day element id used as the keyboard focus
    /// target. Scoped to the rendered month panel so the same calendar date
    /// appearing as a trailing/leading day in another panel gets a distinct id.</summary>
    private string DayId(DateOnly monthDate, DateOnly day)
        => $"{_elementId}-{monthDate.Year:D4}{monthDate.Month:D2}-{day:yyyyMMdd}";

    /// <summary>Full, culture-localized date for the day button's
    /// <c>aria-label</c> (e.g. "Saturday, June 14, 2025"). Uses the same
    /// CurrentCulture the month/day headers are formatted with.</summary>
    private string DayAriaLabel(DateOnly day)
        => day.ToDateTime(TimeOnly.MinValue).ToString("D", System.Globalization.CultureInfo.CurrentCulture);

    /// <summary>The window of months currently on screen. Keyboard focus must
    /// land on a day that belongs to one of these months' own days.</summary>
    private DateOnly FirstDisplayedMonth => new(DisplayDate.Year, DisplayDate.Month, 1);
    private DateOnly LastDisplayedMonthEnd
    {
        get
        {
            var last = DisplayDate.AddMonths(NumberOfMonths - 1);
            return new DateOnly(last.Year, last.Month, DateTime.DaysInMonth(last.Year, last.Month));
        }
    }

    /// <summary>Lazily seeds the roving-tabindex target and keeps it inside the
    /// displayed month window. Preference order: the selected day, then today,
    /// then the first of the displayed month — so the first Tab into the grid
    /// lands somewhere meaningful.</summary>
    private void EnsureFocusedDate()
    {
        bool InWindow(DateOnly d) => d >= FirstDisplayedMonth && d <= LastDisplayedMonthEnd;

        if (_focusedDate is { } f && InWindow(f)) return;

        var preferred = IsRange ? (RangeEnd ?? RangeStart) : Value;
        var today = DateOnly.FromDateTime(DateTime.Today);
        var seed =
            preferred is { } p && InWindow(p) ? p :
            InWindow(today) ? today :
            FirstDisplayedMonth;

        // The tabbable day must be interactive (a native-disabled button can't
        // be Tab-focused), so nudge the seed forward to the first enabled day in
        // the window when the natural choice is disabled.
        if (IsDisabled(seed))
            seed = SkipDisabled(seed, 1);
        _focusedDate = seed;
    }

    /// <summary>Roving tabindex: exactly one day button — the focused day, shown
    /// as a current-month cell — is in the tab sequence; every other day carries
    /// -1 and is reached with the arrow keys. The current-month guard keeps the
    /// count at one even though leading/trailing days repeat the date.</summary>
    private string DayTabIndex(DateOnly day, DateOnly monthDate)
    {
        EnsureFocusedDate();
        return day == _focusedDate && day.Month == monthDate.Month ? "0" : "-1";
    }

    /// <summary>Keeps the roving tabindex aligned when a day receives DOM focus
    /// directly (mouse click or Tab) rather than via arrow-key navigation.</summary>
    private void OnDayFocus(DateOnly day)
    {
        if (_focusedDate != day)
            _focusedDate = day;
    }

    /// <summary>WAI-ARIA grid navigation. Arrow keys move one day (±1) or one
    /// week (±7); Home/End jump to the start/end of the focused week;
    /// PageUp/PageDown change month; Enter/Space select the focused day.
    /// Moving across a month boundary navigates the displayed month and keeps
    /// focus on the correct day.</summary>
    private async Task HandleDayKeyDownAsync(KeyboardEventArgs e, DateOnly monthDate, DateOnly day)
    {
        // Only the tabbable (current-month) cell drives navigation, so repeated
        // leading/trailing copies of the same date don't double-handle the key.
        if (day != _focusedDate || day.Month != monthDate.Month) return;

        switch (e.Key)
        {
            // Directional keys move first, then skip over disabled days (mouse
            // can't select them either) so focus never lands on a non-interactive
            // native-disabled button. SkipDisabled starts at the moved date and
            // continues in the same direction.
            case "ArrowLeft":  await MoveFocusToAsync(SkipDisabled(day.AddDays(-1), -1)); break;
            case "ArrowRight": await MoveFocusToAsync(SkipDisabled(day.AddDays(1), 1)); break;
            case "ArrowUp":    await MoveFocusToAsync(SkipDisabled(day.AddDays(-7), -1)); break;
            case "ArrowDown":  await MoveFocusToAsync(SkipDisabled(day.AddDays(7), 1)); break;
            case "Home":       await MoveFocusToAsync(SkipDisabled(StartOfWeek(day), 1)); break;
            case "End":        await MoveFocusToAsync(SkipDisabled(StartOfWeek(day).AddDays(6), -1)); break;
            case "PageUp":     await MoveFocusToAsync(SkipDisabled(day.AddMonths(-1), 1)); break;
            case "PageDown":   await MoveFocusToAsync(SkipDisabled(day.AddMonths(1), -1)); break;
            // Enter/Space are intentionally NOT handled here: the day cell is a
            // native <button> whose @onclick already calls SelectDay, so handling
            // the key here too fired SelectDay twice — in range mode that set
            // RangeStart and RangeEnd to the same day in a single keypress.
        }
    }

    /// <summary>Returns the first non-disabled day at or beyond <paramref name="from"/>
    /// stepping by <paramref name="step"/> days. Bounded so a fully-disabled run
    /// (or hitting Min/MaxDate) settles rather than looping; if everything in
    /// range is disabled it falls back to the original day (selection there is a
    /// no-op anyway, matching the mouse).</summary>
    private DateOnly SkipDisabled(DateOnly from, int step)
    {
        var candidate = from;
        for (var i = 0; i < 62 && IsDisabled(candidate); i++)
        {
            // AddDays THROWS (it does not clamp) once the result would leave DateOnly's
            // 0001-01-01..9999-12-31 range, so stop there. Min/MaxDate constraints
            // normally settle this loop long before the type bounds are reached.
            DateOnly next;
            try { next = candidate.AddDays(step); }
            catch (ArgumentOutOfRangeException) { break; }
            candidate = next;
        }
        return IsDisabled(candidate) ? from : candidate;
    }

    private DateOnly StartOfWeek(DateOnly day)
    {
        var offset = ((int)day.DayOfWeek - (int)EffectiveFirstDayOfWeek + 7) % 7;
        return day.AddDays(-offset);
    }

    /// <summary>Moves the roving focus to <paramref name="target"/>, navigating
    /// the displayed month if the target falls outside the current window, then
    /// pushes DOM focus onto the target day button via JS interop.</summary>
    private async Task MoveFocusToAsync(DateOnly target)
    {
        // No enabled day in the requested direction (whole run disabled, or the
        // clamp at Min/MaxDate landed on a disabled day): keep focus put so the
        // tabbable day never becomes a non-focusable native-disabled button.
        if (IsDisabled(target)) return;

        _focusedDate = target;

        // Pull the displayed month onto the target so the day actually renders
        // as a current-month cell (the tabbable one) in some visible panel.
        if (target < FirstDisplayedMonth || target > LastDisplayedMonthEnd)
            DisplayDate = new DateOnly(target.Year, target.Month, 1);

        StateHasChanged();

        // The day's home-month panel owns the tabbable copy. With a single month
        // that's DisplayDate; with several it's the panel whose month matches.
        var ownerMonth = NumberOfMonths == 1
            ? DisplayDate
            : new DateOnly(target.Year, target.Month, 1);
        try { await Interop.FocusElement(DayId(ownerMonth, target)); }
        catch (JSDisconnectedException) { }
    }

    private void PreviousMonth() => DisplayDate = DisplayDate.AddMonths(-1);
    private void NextMonth() => DisplayDate = DisplayDate.AddMonths(1);

    private void SwitchToMonthView() => _currentView = CalendarView.Months;
    private void SwitchToYearView() => _currentView = CalendarView.Years;

    private void SelectMonth(int month)
    {
        DisplayDate = new DateOnly(DisplayDate.Year, month, 1);
        _currentView = CalendarView.Days;
    }

    private void SelectYear(int year)
    {
        DisplayDate = new DateOnly(year, DisplayDate.Month, 1);
        _currentView = CalendarView.Months;
    }

    private void PreviousDecade()
    {
        var decadeStart = GetDecadeStart(DisplayDate.Year);
        DisplayDate = new DateOnly(Math.Max(1, decadeStart - 10), DisplayDate.Month, 1);
    }

    private void NextDecade()
    {
        var decadeStart = GetDecadeStart(DisplayDate.Year);
        DisplayDate = new DateOnly(Math.Min(9999, decadeStart + 10), DisplayDate.Month, 1);
    }

    private void PreviousYear()
    {
        DisplayDate = new DateOnly(Math.Max(1, DisplayDate.Year - 1), DisplayDate.Month, 1);
    }

    private void NextYear()
    {
        DisplayDate = new DateOnly(Math.Min(9999, DisplayDate.Year + 1), DisplayDate.Month, 1);
    }

    private RenderFragment RenderMonth(DateOnly monthDate, bool showPrev = true, bool showNext = true) => __builder =>
    {
        @* Fixed 224px content width matches the 7-column day grid (7 × w-8 = 224px),
           so the Days, Months and Years views all render at the same outer width.
           Without this the Months / Years 3-col grid (w-full cells) would collapse
           to its natural width and the picker would visibly resize between views. *@
        <div class="w-[224px] flex flex-col">
        <div class="flex items-center justify-between px-1 mb-2">
            @if (showPrev)
            {
                if (_currentView == CalendarView.Years)
                {
                    <button type="button" aria-label="@L["Calendar.PrevYear"]" class="inline-flex items-center justify-center rounded-md h-11 w-11 sm:h-7 sm:w-7 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="PreviousDecade">
                        <Blazicon Svg="Lucide.ChevronLeft" class="h-4 w-4" />
                    </button>
                }
                else if (_currentView == CalendarView.Months)
                {
                    <button type="button" aria-label="@L["Calendar.PrevYear"]" class="inline-flex items-center justify-center rounded-md h-11 w-11 sm:h-7 sm:w-7 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="PreviousYear">
                        <Blazicon Svg="Lucide.ChevronLeft" class="h-4 w-4" />
                    </button>
                }
                else
                {
                    <button type="button" aria-label="@L["Calendar.PrevMonth"]" class="inline-flex items-center justify-center rounded-md h-11 w-11 sm:h-7 sm:w-7 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-30" disabled="@IsPrevMonthDisabled" @onclick="PreviousMonth">
                        <Blazicon Svg="Lucide.ChevronLeft" class="h-4 w-4" />
                    </button>
                }
            }
            else
            {
                <div class="w-11 sm:w-7"></div>
            }

            @if (_currentView == CalendarView.Years)
            {
                var decadeStart = GetDecadeStart(monthDate.Year);
                <span class="text-sm font-medium">@decadeStart - @(decadeStart + 9)</span>
            }
            else if (_currentView == CalendarView.Months)
            {
                <button type="button" class="text-sm font-medium hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded-md px-2 py-1" @onclick="SwitchToYearView">
                    @monthDate.Year
                </button>
            }
            else
            {
                @* Single combined click target: 1st click → Months view, 2nd click
                   (now in Months view, on the year header) → Years view. Cleaner
                   than two adjacent buttons that look identical but route to
                   different pickers. *@
                <button type="button" class="text-sm font-medium hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded-md px-2 py-1" @onclick="SwitchToMonthView">
                    @monthDate.ToString("MMMM") @monthDate.Year
                </button>
            }

            @if (showNext)
            {
                if (_currentView == CalendarView.Years)
                {
                    <button type="button" aria-label="@L["Calendar.NextYear"]" class="inline-flex items-center justify-center rounded-md h-11 w-11 sm:h-7 sm:w-7 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="NextDecade">
                        <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4" />
                    </button>
                }
                else if (_currentView == CalendarView.Months)
                {
                    <button type="button" aria-label="@L["Calendar.NextYear"]" class="inline-flex items-center justify-center rounded-md h-11 w-11 sm:h-7 sm:w-7 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="NextYear">
                        <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4" />
                    </button>
                }
                else
                {
                    <button type="button" aria-label="@L["Calendar.NextMonth"]" class="inline-flex items-center justify-center rounded-md h-11 w-11 sm:h-7 sm:w-7 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-30" disabled="@IsNextMonthDisabled" @onclick="NextMonth">
                        <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4" />
                    </button>
                }
            }
            else
            {
                <div class="w-11 sm:w-7"></div>
            }
        </div>

        @if (_currentView == CalendarView.Years)
        {
            var decadeStart = GetDecadeStart(monthDate.Year);
            <div class="grid grid-cols-3 gap-2 p-1">
                @for (var y = decadeStart; y < decadeStart + 12; y++)
                {
                    var year = y;
                    var isCurrentYear = year == DateTime.Today.Year;
                    var isSelectedYear = year == monthDate.Year;
                    var yearClass = isSelectedYear
                        ? "inline-flex items-center justify-center rounded-md h-9 w-full text-sm font-medium bg-primary text-primary-foreground"
                        : isCurrentYear
                            ? "inline-flex items-center justify-center rounded-md h-9 w-full text-sm font-medium bg-accent text-accent-foreground"
                            : "inline-flex items-center justify-center rounded-md h-9 w-full text-sm hover:bg-accent hover:text-accent-foreground cursor-pointer focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";
                    <button type="button" class="@yearClass" @onclick="() => SelectYear(year)">@year</button>
                }
            </div>
        }
        else if (_currentView == CalendarView.Months)
        {
            var monthNames = System.Globalization.CultureInfo.CurrentCulture.DateTimeFormat.AbbreviatedMonthNames;
            <div class="grid grid-cols-3 gap-2 p-1">
                @for (var m = 1; m <= 12; m++)
                {
                    var month = m;
                    var isCurrentMonth = month == DateTime.Today.Month && monthDate.Year == DateTime.Today.Year;
                    var isSelectedMonth = month == monthDate.Month;
                    var monthClass = isSelectedMonth
                        ? "inline-flex items-center justify-center rounded-md h-9 w-full text-sm font-medium bg-primary text-primary-foreground"
                        : isCurrentMonth
                            ? "inline-flex items-center justify-center rounded-md h-9 w-full text-sm font-medium bg-accent text-accent-foreground"
                            : "inline-flex items-center justify-center rounded-md h-9 w-full text-sm hover:bg-accent hover:text-accent-foreground cursor-pointer focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";
                    <button type="button" class="@monthClass" @onclick="() => SelectMonth(month)">@monthNames[month - 1]</button>
                }
            </div>
        }
        else
        {
            var gridCols = ShowWeekNumbers ? "grid-cols-8" : "grid-cols-7";
            // Single-month grids carry the per-instance id so JS can attach swipe
            // and the page-scroll suppression for the keyboard nav keys. Multi-
            // month panels share one component so the id is omitted there to
            // avoid duplicate-id collisions (keyboard focus still works — each
            // day button has its own deterministic id).
            var gridId = NumberOfMonths == 1 ? _elementId : null;
            @* role="grid" + role="row"/role="gridcell" give the day grid proper
               table semantics for assistive tech. The week rows use the `contents`
               display so the flat CSS grid layout (and ShowWeekNumbers column) is
               unchanged — the row wrappers add no box, only ARIA structure. *@
            <div id="@gridId" role="grid" aria-label="@monthDate.ToString("MMMM yyyy")" class="grid @gridCols gap-0 text-center">
                <div role="row" class="contents">
                    @if (ShowWeekNumbers)
                    {
                        <div role="columnheader" class="text-xs font-medium text-muted-foreground py-1">#</div>
                    }
                    @foreach (var day in GetDayHeaders())
                    {
                        <div role="columnheader" class="text-xs font-medium text-muted-foreground py-1">@day</div>
                    }
                </div>

                @{ var calDays = GetCalendarDays(monthDate); }
                @for (var row = 0; row < 6; row++)
                {
                    var weekRow = row;
                    <div role="row" class="contents">
                        @if (ShowWeekNumbers)
                        {
                            var weekDate = calDays[weekRow * 7];
                            <div role="rowheader" class="inline-flex items-center justify-center h-8 w-8 text-xs text-muted-foreground">@GetIsoWeekNumber(weekDate)</div>
                        }
                        @for (var col = 0; col < 7; col++)
                        {
                            var d = calDays[weekRow * 7 + col];
                            var dt = d.ToDateTime(TimeOnly.MinValue);
                            var tooltip = DateTooltip?.Invoke(dt);
                            var badge = DateBadge?.Invoke(dt);
                            var isSelectedDay = IsDaySelected(d);
                            <div role="gridcell" aria-selected="@isSelectedDay.ToString().ToLowerInvariant()" class="@RangeBarClasses(d, monthDate, col)">
                                @if (tooltip is not null)
                                {
                                    @* DateTooltip dogfoods the Lumeo <Tooltip> (styled, accessible) instead of
                                       the native title. AsChild keeps aria-describedby on the day button; the
                                       wrapper is forced to `block w-full` so the full-width grid cell is preserved
                                       (the Tooltip root is inline-flex by default, which would shrink the day).
                                       Content is lazy (only mounts on hover) so 42 cells stay cheap. *@
                                    <Tooltip Class="block w-full">
                                        <TooltipTrigger AsChild>
                                            <ChildContentSlot Context="slot">@RenderDay(d, monthDate, badge, slot.Attributes)</ChildContentSlot>
                                        </TooltipTrigger>
                                        <TooltipContent>@tooltip</TooltipContent>
                                    </Tooltip>
                                }
                                else
                                {
                                    @RenderDay(d, monthDate, badge, null)
                                }
                            </div>
                        }
                    </div>
                }
            </div>
        }
        </div> @* close the fixed-width wrapper *@
    };

    public enum CalendarView
    {
        Days,
        Months,
        Years
    }

}
